visualizerParams.ghostCode:
#include <stdio.h>

int factorial(int n) {
    int res = 1;
    for (int i = 1; i <= n; i++) res *= i;
    return res;
}

int main() {
    int n = 145, original = n, sum = 0;
    while (n > 0) {
        sum += factorial(n % 10);
        n /= 10;
    }
    if (sum == original) printf("%d is Strong\n", original);
    else printf("%d is not Strong\n", original);
    return 0;
}

